// Collect people from all 5 search pages into one flat list of items
const out = [];
for (const item of $input.all()) {
  const people = item.json.people || [];
  for (const p of people) {
    if (!p || !p.id) continue;
    out.push({ json: { apollo_id: p.id } });
  }
}
return out;

// Bulk-match accepts up to 10 people per call
const ids = $input.all().map(i => i.json.apollo_id);
return [{ json: { details: ids.map(id => ({ id })) } }];

// Dedupe by email and cap the list at 500
const seen = new Set();
const out = [];
for (const item of $input.all()) {
  const email = (item.json.email || '').toLowerCase().trim();
  if (!email || seen.has(email)) continue;
  seen.add(email);
  out.push(item);
  if (out.length >= 500) break;
}
return out;
